-- Ken's Hardened V2 Fix

local b64_0xllIlII = {}
local char_0x11lIII='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
for i_0xll1I1I=1,#char_0x11lIII do b64_0xllIlII[char_0x11lIII:sub(i_0xll1I1I,i_0xll1I1I)] = i_0xll1I1I - 1 end

function b64_0xllIlII.dec_0xllIIII(d_0xllllII)
    d_0xllllII = string.gsub(d_0xllllII, '[^'..char_0x11lIII..'=]', '')
    local r_0xllIlll = {}
    for i_0xll1I1I=1, #d_0xllllII, 4 do
        local c_0xIlIlII = b64_0xllIlII[d_0xllllII:sub(i_0xll1I1I,i_0xll1I1I)] or 0
        local c_0x1I1Ill = b64_0xllIlII[d_0xllllII:sub(i_0xll1I1I+1,i_0xll1I1I+1)] or 0
        local c_0xll1III, c_0x1IIl1I = 0, 0
        local has3 = true
        local has4 = true
        local ch3 = d_0xllllII:sub(i_0xll1I1I+2,i_0xll1I1I+2)
        if ch3 == "=" then has3 = false else c_0xll1III = b64_0xllIlII[ch3] or 0 end
        local ch4 = d_0xllllII:sub(i_0xll1I1I+3,i_0xll1I1I+3)
        if ch4 == "=" then has4 = false else c_0x1IIl1I = b64_0xllIlII[ch4] or 0 end
        local b_0xll1Ill = c_0xIlIlII * (2^18) + c_0x1I1Ill * (2^12) + c_0xll1III * (2^6) + c_0x1IIl1I
        local b_0xl1111l = math.floor(b_0xll1Ill / (2^16)) % (2^8)
        local b_0xIllllI = math.floor(b_0xll1Ill / (2^8)) % (2^8)
        local b_0xllII1l = b_0xll1Ill % (2^8)
        table.insert(r_0xllIlll, string.char(b_0xl1111l))
        if has3 then table.insert(r_0xllIlll, string.char(b_0xIllllI)) end
        if has4 then table.insert(r_0xllIlll, string.char(b_0xllII1l)) end
    end
    return table.concat(r_0xllIlll)
end


local function bxor_0xIIllIl(a_0x1lIlII,b_0xllI1II)
    if bit32 then return bit32.bxor(a_0x1lIlII,b_0xllI1II) end
    local r_0x1llllI = 0
    for i_0xIII1I1 = 0, 7 do
        local x_0x1II1Il = a_0x1lIlII % 2
        local y_0xIII1l1 = b_0xllI1II % 2
        if x_0x1II1Il ~= y_0xIII1l1 then r_0x1llllI = r_0x1llllI + (2^i_0xIII1I1) end
        a_0x1lIlII = math.floor(a_0x1lIlII / 2)
        b_0xllI1II = math.floor(b_0xllI1II / 2)
    end
    return r_0x1llllI
end


local function bxor_str_0xl1llIl(s_0xllIIlI, k_0x11II1l)
    local r_0xllIlII = {}
    for i_0x1lIll1=1, #s_0xllIIlI do
        local b_0x1l11ll = string.byte(s_0xllIIlI, i_0x1lIll1)
        local kb_0xIIlIIl = string.byte(k_0x11II1l, (i_0x1lIll1-1) % #k_0x11II1l + 1)
        r_0xllIlII[i_0x1lIll1] = string.char(bxor_0xIIllIl(b_0x1l11ll, kb_0xIIlIIl))
    end
    return table.concat(r_0xllIlII)
end


local function getkeys_0xI1lll1()
    local seed = b64_0xllIlII.dec_0xllIIII("VzdrZUtxYWY=")
    local k1_enc = b64_0xllIlII.dec_0xllIIII("MU0fDxMEVRQ=")
    local k2_enc = b64_0xllIlII.dec_0xllIIII("GkUCEjIWGzQ=")
    return bxor_str_0xl1llIl(k1_enc, seed), bxor_str_0xl1llIl(k2_enc, seed)
end


local function cff_0xIl1ll1(a_0xIll1II)
    local st_0xlI11lI = 0
    local res_0xIIlIIl = a_0xIll1II
    while true do
        if st_0xlI11lI == 0 then
            res_0xIIlIIl = res_0xIIlIIl + 1
            st_0xlI11lI = 1
        elseif st_0xlI11lI == 1 then
            res_0xIIlIIl = res_0xIIlIIl * 2
            st_0xlI11lI = 2
        elseif st_0xlI11lI == 2 then
            res_0xIIlIIl = res_0xIIlIIl - 3
            st_0xlI11lI = 3
        else
            break
        end
    end
    return res_0xIIlIIl
end


local function chain_0xIII1l1(x) return x*2 end
local function chain_0xlI1Il1(x) return chain_0xIII1l1(x)+1 end


local d_0xIIlIIl = {
  {op=255, val="", is_enc=true},
}
local pc_0xIIIl1I = 1
local stk_0xlllIll = {}
stk_0xlllIll._jmp = nil


local disp_0xIl1llI = {
    [0] = function() end,
    [1] = function(s, v) table.insert(s, v) end,
    [2] = function(s, v) table.insert(s, _G[v]) end,
    [3] = function(s, v) local val=table.remove(s); _G[v]=val end,
    [4] = function(s, _) table.insert(s, {}) end,
    [5] = function(s, _) local val=table.remove(s); local key=table.remove(s); local t=table.remove(s); t[key]=val; table.insert(s, t) end,
    [16] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a+b) end,
    [17] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a-b) end,
    [18] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a*b) end,
    [19] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a/b) end,
    [32] = function(s, n) 
        local args = {}
        for i=1,tonumber(n) do table.insert(args, 1, table.remove(s)) end
        local f = table.remove(s)
        if type(f) == "function" then
            local result = {f(unpack(args))}
            for _,v in ipairs(result) do table.insert(s, v) end
        else
            print("[LBI] Not a function: "..tostring(f))
        end
    end,
    [33] = function(s) return table.remove(s) end,
    [48] = function(s, offset) 
        local cond = table.remove(s)
        if not cond then 
            s._jmp = tonumber(offset)
        end
    end,
    [49] = function(s, offset)
        s._jmp = tonumber(offset)
    end,
    [255] = function(s, v)
        local fn, err = loadstring(v)
        if not fn then
            print("[LBI] Load error: "..tostring(err))
        else
            local ok, res = pcall(fn)
            if not ok then print("[LBI] Run error: "..tostring(res)) end
        end
    end
}



local k1, k2 = getkeys_0xI1lll1()

local state_0xI1lIll = 0
while true do
    if state_0xI1lIll == 0 then  -- FETCH
        if pc_0xIIIl1I > #d_0xIIlIIl then break end
        local inst = d_0xIIlIIl[pc_0xIIIl1I]
        local opcode = inst.op
        local val = inst.val
        if inst.is_enc then
            local d = b64_0xllIlII.dec_0xllIIII(val)
            d = bxor_str_0xl1llIl(d, k2)
            val = bxor_str_0xl1llIl(d, k1)
        end
        stk_0xlllIll._jmp = nil
        pc_0xIIIl1I = pc_0xIIIl1I + 1
        cur_op_0xllllII = opcode
        cur_val_0xIIIlll = val
        state_0xI1lIll = 1

    elseif state_0xI1lIll == 1 then  -- EXECUTE
        local handler = disp_0xIl1llI[cur_op_0xllllII]
        if handler then
            handler(stk_0xlllIll, cur_val_0xIIIlll)
        end
        if stk_0xlllIll._jmp then
            pc_0xIIIl1I = pc_0xIIIl1I + stk_0xlllIll._jmp
        end
        state_0xI1lIll = 0
    else
        break
    end
end
